import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldCheck, Box } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    // --- State Management ---
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    // --- 1. Fetch History & Initial Holdings ---
    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) {
                    initializeStocks(res.data[0].holdings);
                }
            } catch (err) {
                console.error("VAULT_SYNC_ERROR");
            }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            
            setStocks(tickers.map(t => ({
                ticker: t,
                price: Math.floor(Math.random() * 2000) + 500,
                change: 0.00
            })));
        } catch (e) {
            setStocks([]);
        }
    };

    // --- 2. Live WebSocket Pulse ---
    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);

        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 8;
                return {
                    ...s,
                    price: parseFloat((s.price + move).toFixed(2)),
                    change: parseFloat(move.toFixed(2))
                };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    // --- 3. Navigation ---
    const navigate = (direction) => {
        let newIndex = currentIndex + direction;
        if (newIndex >= 0 && newIndex < history.length) {
            setCurrentIndex(newIndex);
            initializeStocks(history[newIndex].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div style={appWrapper}>
            <div style={terminalContainer}>
                {/* ── Fixed Header ── */}
                <header style={headerSection}>
                    <div style={navRow}>
                        <button 
                            onClick={() => navigate(1)} 
                            disabled={currentIndex === history.length - 1}
                            style={navBtn(currentIndex === history.length - 1)}
                        >
                            <ChevronLeft size={16}/> PREV
                        </button>

                        <div style={nodeDisplay}>
                            <Box size={14} color="#10b981" />
                            <span style={nodeTitle}>{activeNode ? activeNode.goal : 'SYNCHRONIZING_CORE...'}</span>
                        </div>

                        <button 
                            onClick={() => navigate(-1)} 
                            disabled={currentIndex === 0}
                            style={navBtn(currentIndex === 0)}
                        >
                            NEXT <ChevronRight size={16}/>
                        </button>
                    </div>

                    <div style={statusRow}>
                        <div style={statusItem(isConnected)}>
                            <Activity size={12} /> {isConnected ? 'LIVE_UPLINK' : 'LINK_LOST'}
                        </div>
                        <div style={riskItem}>
                            <ShieldCheck size={12} /> RISK_EXPOSURE: {activeNode?.risk_score || 0}%
                        </div>
                        <div style={counterTag}>{currentIndex + 1} / {history.length}</div>
                    </div>
                </header>

                {/* ── Internal Scrollable Grid ── */}
                <main style={scrollContent}>
                    <div style={gridContainer}>
                        {stocks.map((stock, i) => (
                            <div key={i} style={stockCard(stock.change >= 0)}>
                                <div style={cardTop}>
                                    <span style={tickerSymbol}>{stock.ticker}</span>
                                    <Zap size={14} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                                </div>
                                <div style={priceLabel}>MARKET_VAL</div>
                                <div style={priceValue}>₹{stock.price.toLocaleString()}</div>
                                <div style={changeValue(stock.change >= 0)}>
                                    {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                    {stock.change >= 0 ? '+' : ''}{stock.change}%
                                </div>
                            </div>
                        ))}
                    </div>
                    {stocks.length === 0 && <div style={emptyMessage}>AWAITING_PORTFOLIO_DATA...</div>}
                </main>
            </div>
        </div>
    );
};

/* --- Terminal Style Definitions --- */
const appWrapper = {
    height: 'calc(100vh - 70px)', // Height restricted to screen
    width: '100%',
    display: 'flex',
    justifyContent: 'center',
    background: '#07080a',
    padding: '20px',
    boxSizing: 'border-box',
    overflow: 'hidden' // Disables page-level scrolling
};

const terminalContainer = {
    width: '100%',
    maxWidth: '1200px',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    background: '#0a0b0e',
    borderRadius: '20px',
    border: '1px solid #1a1d23',
    boxShadow: '0 20px 50px rgba(0,0,0,0.5)',
    overflow: 'hidden'
};

const headerSection = {
    padding: '1.2rem 1.5rem',
    background: '#0d0f14',
    borderBottom: '1px solid #1a1d23',
    flexShrink: 0
};

const navRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' };
const navBtn = (disabled) => ({
    background: 'none', border: 'none', color: disabled ? '#333' : '#10b981',
    cursor: disabled ? 'default' : 'pointer', fontSize: '0.65rem', fontWeight: 800,
    display: 'flex', alignItems: 'center', gap: '5px', fontFamily: 'monospace'
});

const nodeDisplay = { 
    display: 'flex', alignItems: 'center', gap: '10px', background: '#111318', 
    padding: '6px 14px', borderRadius: '6px', border: '1px solid #1a1d23',
    maxWidth: '70%'
};

const nodeTitle = { fontSize: '0.75rem', fontWeight: 700, color: '#fff', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' };

const statusRow = { display: 'flex', gap: '1.5rem', alignItems: 'center' };
const statusItem = (on) => ({ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.55rem', fontWeight: 900, color: on ? '#10b981' : '#ef4444', fontFamily: 'monospace' });
const riskItem = { display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.55rem', fontWeight: 900, color: '#666', fontFamily: 'monospace' };
const counterTag = { marginLeft: 'auto', fontSize: '0.6rem', color: '#10b981', background: 'rgba(16,185,129,0.1)', padding: '2px 8px', borderRadius: '4px' };

const scrollContent = { 
    flex: 1, 
    padding: '1.5rem', 
    overflowY: 'auto', // ONLY this area scrolls
    scrollbarWidth: 'thin',
    scrollbarColor: '#1a1d23 transparent'
};

const gridContainer = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: '1rem' };

const stockCard = (up) => ({
    padding: '1.2rem', background: '#111318', border: '1px solid #1a1d23',
    borderRadius: '12px', borderLeft: `3px solid ${up ? '#10b981' : '#ef4444'}`,
    transition: 'border 0.2s'
});

const cardTop = { display: 'flex', justifyContent: 'space-between', marginBottom: '0.8rem' };
const tickerSymbol = { fontSize: '0.75rem', fontWeight: 900, color: '#10b981', fontFamily: 'monospace' };
const priceLabel = { fontSize: '0.5rem', color: '#444', fontWeight: 800, marginBottom: '2px' };
const priceValue = { fontSize: '1.6rem', fontWeight: 900, color: '#fff', fontFamily: 'monospace' };
const changeValue = (up) => ({ marginTop: '8px', fontSize: '0.8rem', fontWeight: 800, color: up ? '#10b981' : '#ef4444', display: 'flex', alignItems: 'center', gap: '5px' });

const emptyMessage = { textAlign: 'center', padding: '4rem', color: '#444', fontSize: '0.75rem', fontFamily: 'monospace' };

export default LiveMarketPage;
